import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    if (localStorage.getItem("token")) {
      navigate("/Homepage", { replace: true });
    }
  }, [navigate]);
  async function login(e) {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", {
        email,
        password,
      });
      // Save JWT token to localStorage
      localStorage.setItem("token", res.data.token);
      localStorage.setItem("username", res.data.username);
      setError("");
      // Redirect to home or dashboard page on successful login
      // navigate("/Homepage", { replace: true });
    } catch (e) {
      if (e.response && e.response.data && e.response.data.error) {
        setError(e.response.data.error);
      } else {
        setError("Login failed. Please try again.");
      }
    }
  }

  function handleRegisterRedirect() {
    navigate("/register");
  }

  const inputStyle = {
    width: "100%",
    padding: "10px 14px",
    borderRadius: 8,
    border: "1px solid #D1D8ED",
    fontSize: 16,
    margin: "14px 0 0 0",
    boxSizing: "border-box",
  };

  return (
    <div
      style={{
        background: "#EAEFF9",
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <form
        onSubmit={login}
        style={{
          background: "#fff",
          padding: "2.5rem",
          borderRadius: 18,
          boxShadow: "0 4px 16px #BDBDBD26",
          width: 350,
        }}
      >
        <h2 style={{ color: "#5D5FEF", textAlign: "center", marginBottom: 24 }}>
          Login
        </h2>
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={inputStyle}
        />
        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={inputStyle}
        />
        <button
          type="submit"
          style={{
            background: "#5D5FEF",
            color: "#fff",
            borderRadius: 12,
            border: 0,
            padding: "10px",
            fontWeight: 600,
            fontSize: 16,
            width: "100%",
            marginTop: 14,
            cursor: "pointer",
          }}
        >
          Login
        </button>
        {error && <p style={{ color: "#C44737", marginTop: 14 }}>{error}</p>}
        <button
          type="button"
          onClick={handleRegisterRedirect}
          style={{
            background: "#fff",
            color: "#5D5FEF",
            borderRadius: 12,
            border: "1px solid #5D5FEF",
            padding: "10px",
            fontWeight: 600,
            fontSize: 16,
            width: "100%",
            marginTop: 20,
            cursor: "pointer",
          }}
        >
          Create Account
        </button>
      </form>
    </div>
  );
}
